    it('should dismiss package toast when X is clicked', () => {
      mockPackagesState.detectedMissingPackages = ['lodash'];
      mockPackageMetadataState.packageMetadata = {
        lodash: { name: 'lodash', version: '4.17.21' },
      };

      render(<ResultDisplay />);
      // Find the dismiss button (X icon button)
      const dismissButtons = screen.getAllByRole('button');
      // The dismiss button is inside each toast, has an X icon
      const dismissBtn = dismissButtons.find(
        (btn) =>
          btn.querySelector('svg') &&
          btn.classList.contains('text-muted-foreground')
      );
      expect(dismissBtn).toBeDefined();
      fireEvent.click(dismissBtn!);

      expect(mockPackageMetadataState.setDismissedPackages).toHaveBeenCalled();
    });
  });

  describe('FilterToggle counts', () => {
    it('should show count badges for each console type', () => {
      mockCodeStoreState.result = [
        { element: { content: 'log1', consoleType: 'log' } },
        { element: { content: 'log2', consoleType: 'log' } },
        { element: { content: 'warn1', consoleType: 'warn' } },
        { element: { content: 'info1', consoleType: 'info' } },
        {
          type: 'error',
          element: { content: 'err1', consoleType: 'error' },
        },
      ];

      render(<ResultDisplay />);

      // Find the filter buttons and check counts
      const logButton = screen.getByText('Log').closest('button')!;
      const warnButton = screen.getByText('Warn').closest('button')!;
      const infoButton = screen.getByText('Info').closest('button')!;
      const errorButton = screen.getByText('Error').closest('button')!;

      expect(logButton.textContent).toContain('2');
      expect(warnButton.textContent).toContain('1');
      expect(infoButton.textContent).toContain('1');
      expect(errorButton.textContent).toContain('1');
    });
  });
});

import { useMemo } from 'react';
import { useEditorTabsStore } from '../store/storeHooks';
import { useSettingsStore } from '../store/storeHooks';
import { themes } from '../themes';
import Editor, { Monaco } from '@monaco-editor/react';
import type { editor } from 'monaco-editor';
import { Filter, Wrench } from 'lucide-react';
import clsx from 'clsx';
import { ConsoleInput } from './ConsoleInput';
import { PackagePrompts } from './PackagePrompts';

function ResultDisplay() {
  const { tabs, activeTabId } = useEditorTabsStore();
  const activeTab = useMemo(() => tabs.find(t => t.id === activeTabId), [tabs, activeTabId]);

  const elements = activeTab?.result || [];
  const code = activeTab?.code || '';
  const {
    themeName,
    fontSize,
    alignResults,
    consoleFilters,
    setConsoleFilters,
  } = useSettingsStore();

  const executionError = useMemo(
    () =>
      elements?.find(
        (e) => e.type === 'error' || e.element?.consoleType === 'error'
      ),
    [elements]
  );

  const handleAutoFix = () => {
    if (
      executionError?.element?.content &&
      (
        window as Window & {
          triggerAIAutoCorrection?: (content: string) => void;
        }
      ).triggerAIAutoCorrection
    ) {
      (
        window as Window & {
          triggerAIAutoCorrection?: (content: string) => void;
        }
      ).triggerAIAutoCorrection!(String(executionError.element.content));
    }
  };



  const toggleFilter = (type: keyof typeof consoleFilters) => {
    setConsoleFilters({ [type]: !consoleFilters[type] });
  };

  const filters = consoleFilters;



  function handleEditorWillMount(monaco: Monaco) {
    // Register all themes
    Object.entries(themes).forEach(([name, themeData]) => {
      monaco.editor.defineTheme(name, themeData as editor.IStandaloneThemeData);
    });

    // Access typescript defaults safely through type casting
    interface TSDefaults {
      setEagerModelSync(value: boolean): void;
    }
    interface TSLanguages {
      javascriptDefaults?: TSDefaults;
    }
    const ts = (monaco.languages as unknown as { typescript: TSLanguages })
      .typescript;
    if (ts?.javascriptDefaults) {
      ts.javascriptDefaults.setEagerModelSync(true);
    }
  }

  const displayValue = useMemo(() => {
    if (!elements || elements.length === 0) return '';

    // Filter elements based on type
    const filteredElements = elements.filter((e) => {
      if (e.action) return false; // Filter out actions (handled separately)

      if (e.type === 'error') return filters.error;

      // Handle console types
      const consoleType = e.element?.consoleType || 'log';
      if (consoleType === 'warn') return filters.warn;
      if (consoleType === 'error') return filters.error;
      if (consoleType === 'info') return filters.info;

      // Default to log
      return filters.log;
    });

    if (!alignResults) {
      return filteredElements
        .map((data) => data.element?.content || '')
        .join('\n');
    }

    // Align results with source (keep alignment for filtered items if they persist?
    // Actually if we filter out, we probably shouldn't show them at all,
    // but for 'align', we need to respect the line number.
    // If a line is filtered, it should be empty on that line.)

    // To maintain alignment, we iterate original lines, but only content from filtered elements.

    // Better approach: Use filteredElements.
    // If aligned mode is ON, and I filter out errors, the error on line 5 disappears, line 5 has no result.

    const sourceLineCount = code.split('\n').length;
    const maxLine = Math.max(
      sourceLineCount,
      ...filteredElements.map((e) => e.lineNumber || 0)
    );
    const lines = new Array(maxLine).fill('');

    filteredElements.forEach((data) => {
      if (data.lineNumber && data.lineNumber > 0) {
        // Line numbers are 1-based, array is 0-based
        const current = lines[data.lineNumber - 1];
        const content = data.element?.content || '';
        lines[data.lineNumber - 1] = current
          ? `${current} ${content}`
          : content;
      } else {
        // Append results without line numbers (like global errors) to the end
        lines.push(data.element?.content || '');
      }
    });

    // Trim empty lines at the end if they exceed source code
    // (Optional, but keeps it clean)
    return lines.join('\n');
  }, [elements, alignResults, code, filters]);



  return (
    <div
      className="h-full flex flex-col text-foreground bg-background relative overflow-hidden"
      data-testid="result-panel"
    >
      {/* Console Toolbar */}
      <div className="flex items-center justify-between px-3 py-2 border-b border-border bg-muted/20 shrink-0">
        <div className="flex items-center gap-1.5">
          <div className="mr-2 flex items-center text-muted-foreground">
            <Filter className="w-3.5 h-3.5 mr-1.5" />
            <span className="text-xs font-medium">Filters:</span>
          </div>

          <FilterToggle
            active={filters.log}
            onClick={() => toggleFilter('log')}
            label="Log"
            count={
              elements.filter(
                (e) =>
                  !e.action &&
                  (e.element?.consoleType === 'log' ||
                    (!e.element?.consoleType && e.type !== 'error'))
              ).length
            }
          />
          <FilterToggle
            active={filters.info}
            onClick={() => toggleFilter('info')}
            label="Info"
            color="text-info"
            count={
              elements.filter((e) => e.element?.consoleType === 'info').length
            }
          />
          <FilterToggle
            active={filters.warn}
            onClick={() => toggleFilter('warn')}
            label="Warn"
            color="text-amber-500"
            count={
              elements.filter((e) => e.element?.consoleType === 'warn').length
            }
          />
          <FilterToggle
            active={filters.error}
            onClick={() => toggleFilter('error')}
            label="Error"
            color="text-destructive"
            count={
              elements.filter(
                (e) => e.type === 'error' || e.element?.consoleType === 'error'
              ).length
            }
          />
        </div>
        {executionError && (
          <button
            onClick={handleAutoFix}
            className="flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium bg-destructive/10 hover:bg-destructive/20 text-destructive rounded-md transition-colors mr-2"
          >
            <Wrench className="w-3.5 h-3.5" />
            Auto-Fix
          </button>
        )}
      </div>

      <div className="flex-1 relative min-h-0">
        <Editor
          theme={themeName}
          path="result-output.js"
          options={{
            automaticLayout: true,
            minimap: {
              enabled: false,
            },
            overviewRulerLanes: 0,
            scrollbar: {
              vertical: 'auto',
              horizontal: 'auto',
            },
            fontSize,
            wordWrap: 'on',
            readOnly: true,
            lineNumbers: 'off',
            renderLineHighlight: 'none',
            showUnused: false,
            suggest: {
              selectionMode: 'never',
              previewMode: 'prefix',
            },
          }}
          defaultLanguage="javascript"
          value={displayValue || '// Waiting for output...'}
          beforeMount={handleEditorWillMount}
        />
      </div>

      <ConsoleInput />

      <PackagePrompts />
    </div>
  );
}

export default ResultDisplay;

function FilterToggle({
  active,
  onClick,
  label,
  color,
  count,
}: {
  active: boolean;
  onClick: () => void;
  label: string;
  color?: string;
  count: number;
}) {
  // Only show count if > 0
  const showCount = count > 0;

  return (
    <button
      onClick={onClick}
      className={clsx(
        'px-2 py-1 rounded text-xs font-medium border flex items-center gap-1.5 transition-all select-none',
        active
          ? 'bg-background border-border shadow-sm text-foreground'
          : 'bg-muted/50 border-transparent text-muted-foreground opacity-70 hover:opacity-100'
      )}
    >
      <div
        className={clsx(
          'w-2 h-2 rounded-full',
          active ? color || 'bg-foreground' : 'bg-muted-foreground/50'
        )}
      />
      {label}
      {showCount && (
        <span className="text-[10px] opacity-60 bg-muted px-1 rounded-sm min-w-[14px] text-center">
          {count}
        </span>
      )}
    </button>
  );
}

import React from 'react';
import { m, AnimatePresence } from 'framer-motion';
import { X, Plus, FileCode, FileJson, Hash } from 'lucide-react';
import clsx from 'clsx';
import { useEditorTabsStore } from '../store/storeHooks';

function getLanguageIcon(language: string) {
    switch (language) {
        case 'javascript':
        case 'typescript':
            return <FileCode className="w-3.5 h-3.5 text-yellow-500" />;
        case 'python':
            return <Hash className="w-3.5 h-3.5 text-blue-500" />;
        case 'json':
            return <FileJson className="w-3.5 h-3.5 text-green-500" />;
        default:
            return <FileCode className="w-3.5 h-3.5 text-muted-foreground" />;
    }
}

export function TabBar() {
    const { tabs, activeTabId, setActiveTab, closeTab, addTab } = useEditorTabsStore();

    const handleDragStart = (e: React.DragEvent, id: string) => {
        e.dataTransfer.setData('text/plain', id);
    };

    const handleDrop = (e: React.DragEvent, targetId: string) => {
        e.preventDefault();
        const sourceId = e.dataTransfer.getData('text/plain');
        if (sourceId && sourceId !== targetId) {
            // Future implementation: Drag and drop to reorder
        }
    };

    const handleDragOver = (e: React.DragEvent) => {
        e.preventDefault();
    };

    return (
        <div className="flex bg-background border-b border-border/40 overflow-x-auto overflow-y-hidden custom-scrollbar h-10 shrink-0 select-none">
            <AnimatePresence initial={false}>
                {tabs.map((tab) => {
                    const isActive = tab.id === activeTabId;
                    return (
                        <m.div
                            layout
                            initial={{ opacity: 0, x: -20 }}
                            animate={{ opacity: 1, x: 0 }}
                            exit={{ opacity: 0, scale: 0.9 }}
                            transition={{ duration: 0.2 }}
                            key={tab.id}
                            className={clsx(
                                "group relative flex items-center min-w-[120px] max-w-[200px] h-full border-r border-border/40 cursor-pointer transition-colors",
                                isActive ? "bg-card" : "bg-muted/30 hover:bg-muted/50"
                            )}
                            onClick={() => setActiveTab(tab.id)}
                            draggable
                            onDragStart={(e: any) => handleDragStart(e, tab.id)}
                            onDrop={(e: any) => handleDrop(e, tab.id)}
                            onDragOver={(e: any) => handleDragOver(e)}
                        >
                            <div
                                className={clsx(
                                    "absolute top-0 left-0 w-full h-[2px] transition-colors",
                                    isActive ? "bg-primary" : "bg-transparent group-hover:bg-primary/20"
                                )}
                            />

                            <div className="flex flex-1 items-center gap-2 px-3 overflow-hidden">
                                <div className="shrink-0 flex items-center">
                                    {tab.isExecuting ? (
                                        <svg className="animate-spin h-3.5 w-3.5 text-primary" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                                            <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                                            <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                                        </svg>
                                    ) : (
                                        getLanguageIcon(tab.language)
                                    )}
                                </div>

                                <span className={clsx(
                                    "text-xs truncate transition-colors",
                                    isActive ? "text-foreground font-medium" : "text-muted-foreground group-hover:text-foreground/80"
                                )}>
                                    {tab.title}
                                </span>

                                {/* Pending execution dot */}
                                {tab.isPendingRun && !tab.isExecuting && (
                                    <div className="w-1.5 h-1.5 rounded-full bg-amber-500 animate-pulse ml-auto shrink-0" />
                                )}
                            </div>

                            <button
                                onClick={(e) => {
                                    e.stopPropagation();
                                    closeTab(tab.id);
                                }}
                                className={clsx(
                                    "mx-1 shrink-0 p-1 rounded-md transition-all",
                                    isActive
                                        ? "opacity-100 hover:bg-accent text-muted-foreground hover:text-foreground"
                                        : "opacity-0 group-hover:opacity-100 hover:bg-muted-foreground/20 text-muted-foreground"
                                )}
                            >
                                <X className="w-3.5 h-3.5" />
                            </button>
                        </m.div>
                    );
                })}
            </AnimatePresence>

            <button
                onClick={() => addTab(`script-${tabs.length + 1}.js`)}
                className="flex items-center justify-center w-10 h-10 hover:bg-muted/50 transition-colors text-muted-foreground hover:text-foreground shrink-0 border-r border-border/40"
                title="Nueva Pestaña (Ctrl+T)"
            >
                <Plus className="w-4 h-4" />
            </button>
        </div>
    );
}

// AI Provider Factory using Vercel AI SDK 6
// https://v6.ai-sdk.dev/providers/ai-sdk-providers
/* global RequestInfo, RequestInit */
import { createOpenAI } from '@ai-sdk/openai';
import { createAnthropic } from '@ai-sdk/anthropic';
import { createGoogleGenerativeAI } from '@ai-sdk/google';
import type { AIProvider, CustomProviderConfig } from './types';
import type { LanguageModel } from 'ai';

export interface ProviderInstance {
  model: LanguageModel;
  provider: AIProvider;
  modelId: string;
}

export interface LocalProviderConfig {
  baseURL: string;
  modelId: string;
  apiKey?: string;
}

type ProxyRequestPayload = {
  url: string;
  method: string;
  headers: Record<string, string>;
  body?: string;
};

function isRequestStreaming(body: string | undefined, headers: Headers): boolean {
  const accept = headers.get('accept') || '';
  if (accept.includes('text/event-stream')) return true;
  if (!body) return false;

  return /"stream"\s*:\s*true/i.test(body);
}

async function buildProxyRequestPayload(
  input: RequestInfo | URL,
  init?: RequestInit
): Promise<ProxyRequestPayload> {
  const request = input instanceof Request ? input : new Request(input, init);
  const headers: Record<string, string> = {};
  request.headers.forEach((value, key) => {
    headers[key] = value;
  });

  let body: string | undefined;
  if (request.method !== 'GET' && request.method !== 'HEAD') {
    body = await request.text();
  }

  return {
    url: request.url,
    method: request.method,
    headers,
    body,
  };
}

function createProxyBackedFetch(): typeof fetch {
  return async (input: RequestInfo | URL, init?: RequestInit) => {
    const fallbackFetch = async () => fetch(input, init);
    if (typeof window === 'undefined' || !window.aiProxy?.fetch) {
      return fallbackFetch();
    }

    const payload = await buildProxyRequestPayload(input, init);
    const headers = new Headers(payload.headers);
    const useStreamingProxy = isRequestStreaming(payload.body, headers);

    if (useStreamingProxy) {
      let streamController:
        | ReadableStreamDefaultController<Uint8Array>
        | undefined;
      let settled = false;
      let streamHandle: { abort: () => void } | null = null;
      const textEncoder = new TextEncoder();

      const stream = new ReadableStream<Uint8Array>({
        start(controller) {
          streamController = controller;
        },
        cancel() {
          streamHandle?.abort();
        },
      });

      if (init?.signal) {
        init.signal.addEventListener('abort', () => {
          streamHandle?.abort();
          streamController?.error(
            new DOMException('The operation was aborted.', 'AbortError')
          );
        });
      }

      return new Promise<Response>((resolve, reject) => {
        window.aiProxy!.streamFetch(
          payload,
          (chunk) => {
            if (!settled) {
              settled = true;
              resolve(
                new Response(stream, {
                  status: 200,
                  headers: {
                    'content-type': 'text/event-stream',
                  },
                })
              );
            }

            streamController?.enqueue(textEncoder.encode(chunk));
          },
          () => {
            if (!settled) {
              settled = true;
              resolve(
                new Response(stream, {
                  status: 200,
                  headers: {
                    'content-type': 'text/event-stream',
                  },
                })
              );
            }
            streamController?.close();
          },
          (error) => {
            const message =
              typeof error?.body === 'string' && error.body.length > 0
                ? error.body
                : error?.statusText || 'Proxy stream request failed';

            if (!settled) {
              settled = true;
              reject(new Error(message));
            } else {
              streamController?.error(new Error(message));
            }
          }
        )
          .then((handle: any) => {
            streamHandle = handle;
          })
          .catch((error: any) => {
            reject(
              error instanceof Error
                ? error
                : new Error('Proxy stream setup failed')
            );
          });
      });
    }

    const response = await window.aiProxy.fetch(payload);

    return new Response(response.body, {
      status: response.status,
      statusText: response.statusText,
      headers: response.headers,
    });
  };
}

// Create provider instance based on configuration
export function createProviderInstance(
  provider: AIProvider,
  apiKey: string,
  modelId: string,
  localConfig?: LocalProviderConfig,
  customConfig?: CustomProviderConfig
): ProviderInstance {
  let model: LanguageModel;
  const effectiveModelId = customConfig?.modelId || modelId;
  const proxyFetch = createProxyBackedFetch();

  switch (provider) {
    case 'local': {
      if (!localConfig?.baseURL) {
        throw new Error('Base URL is required for local provider');
      }
      // Use OpenAI-compatible API for local servers (LM Studio, Ollama, etc.)
      const localProvider = createOpenAI({
        baseURL: localConfig.baseURL,
        apiKey: localConfig.apiKey || 'not-needed',
        fetch: proxyFetch,
      });
      model = localProvider.chat(localConfig.modelId || modelId);
      break;
    }
    case 'openai': {
      if (!apiKey) {
        throw new Error('API key not configured for OpenAI');
      }
      // Support custom URL for OpenAI-compatible APIs
      const openaiConfig: Parameters<typeof createOpenAI>[0] = { apiKey };
      if (customConfig?.baseURL) {
        openaiConfig.baseURL = customConfig.baseURL;
      }
      openaiConfig.fetch = proxyFetch;
      const openai = createOpenAI(openaiConfig);
      // Use .chat() for custom models to ensure compatibility
      model = customConfig?.baseURL
        ? openai.chat(effectiveModelId)
        : openai(effectiveModelId);
      break;
    }
    case 'anthropic': {
      if (!apiKey) {
        throw new Error('API key not configured for Anthropic');
      }
      // Support custom URL for Anthropic-compatible APIs
      const anthropicConfig: Parameters<typeof createAnthropic>[0] = { apiKey };
      if (customConfig?.baseURL) {
        anthropicConfig.baseURL = customConfig.baseURL;
      }
      anthropicConfig.fetch = proxyFetch;
      const anthropic = createAnthropic(anthropicConfig);
      model = anthropic(effectiveModelId);
      break;
    }
    case 'google': {
      if (!apiKey) {
        throw new Error('API key not configured for Google');
      }
      const google = createGoogleGenerativeAI({ apiKey, fetch: proxyFetch });
      model = google(effectiveModelId);
      break;
    }
    default:
      throw new Error(`Unknown provider: ${provider}`);
  }

  return { model, provider, modelId: effectiveModelId };
}

// Validate API key format (basic validation)
export function validateApiKeyFormat(
  provider: AIProvider,
  apiKey: string
): boolean {
  if (provider === 'local') {
    return true;
  }

  if (!apiKey || apiKey.trim().length === 0) {
    return false;
  }

  switch (provider) {
    case 'openai':
      // OpenAI keys start with 'sk-' (allow any key for custom endpoints)
      return apiKey.length > 10;
    case 'anthropic':
      // Anthropic keys start with 'sk-ant-' (allow any key for custom endpoints)
      return apiKey.length > 10;
    case 'google':
      return apiKey.length >= 30;
    default:
      return apiKey.length > 10;
  }
}

// Validate local server URL
export function validateLocalServerURL(url: string): boolean {
  if (!url || url.trim().length === 0) {
    return false;
  }
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
}

// Get provider display name
export function getProviderDisplayName(provider: AIProvider): string {
  const names: Record<AIProvider, string> = {
    local: 'Local Server',
    openai: 'OpenAI',
    anthropic: 'Anthropic',
    google: 'Google Gemini',
  };
  return names[provider] || provider;
}

import { useRef, useCallback } from 'react';
import type { editor } from 'monaco-editor';
import { useDebouncedFunction } from '../useDebounce';

interface DetectionResult {
    monacoId: string;
    confidence: number;
    isStale?: boolean;
}

export function useEditorChangeHandler({
    monacoRef,
    setCode,
    lastLocalCodeRef,
    lastCursorPositionRef,
    debouncedRunner,
    language,
    setLanguage,
    detectLanguageSync,
    detectLanguageAsync,
    incrementDetectionVersion,
    getDetectionVersion
}: {
    monacoRef: React.MutableRefObject<editor.IStandaloneCodeEditor | null>;
    setCode: (code: string) => void;
    lastLocalCodeRef: React.MutableRefObject<string | null>;
    lastCursorPositionRef: React.MutableRefObject<any>;
    debouncedRunner: (code: string) => void;
    language: string;
    setLanguage: (lang: string) => void;
    detectLanguageSync: (code: string) => DetectionResult;
    detectLanguageAsync: (code: string) => Promise<DetectionResult>;
    incrementDetectionVersion: () => number;
    getDetectionVersion: () => number;
}) {
    const lastDetectedRef = useRef<string>('typescript');
    const detectionInProgressRef = useRef<boolean>(false);

    const languageRef = useRef(language);
    languageRef.current = language;

    const setLanguageRef = useRef(setLanguage);
    setLanguageRef.current = setLanguage;

    const detectLanguageAsyncRef = useRef(detectLanguageAsync);
    detectLanguageAsyncRef.current = detectLanguageAsync;

    const detectLanguageSyncRef = useRef(detectLanguageSync);
    detectLanguageSyncRef.current = detectLanguageSync;

    const incrementDetectionVersionRef = useRef(incrementDetectionVersion);
    incrementDetectionVersionRef.current = incrementDetectionVersion;

    const getDetectionVersionRef = useRef(getDetectionVersion);
    getDetectionVersionRef.current = getDetectionVersion;

    const debouncedLanguageDetection = useDebouncedFunction(
        async (value: string, versionAtStart: number) => {
            if (detectionInProgressRef.current || !value || value.trim().length === 0)
                return;

            detectionInProgressRef.current = true;
            try {
                const detected = await detectLanguageAsyncRef.current(value);
                const currentLang = languageRef.current;
                const currentVersion = getDetectionVersionRef.current();

                if (currentVersion !== versionAtStart) {
                    return;
                }

                if (detected.isStale) {
                    return;
                }

                if (detected.monacoId !== currentLang && detected.confidence > 0.7) {
                    lastDetectedRef.current = detected.monacoId;
                    setLanguageRef.current(detected.monacoId);
                }
            } catch (error) {
                console.error('[Editor] ML detection failed:', error);
            } finally {
                detectionInProgressRef.current = false;
            }
        },
        250
    );

    const handler = useCallback(
        (value: string | undefined) => {
            if (value !== undefined) {
                if (monacoRef.current) {
                    lastCursorPositionRef.current = monacoRef.current.getPosition();
                }
                lastLocalCodeRef.current = value;
                setCode(value);

                const newVersion = incrementDetectionVersionRef.current();

                try {
                    const quick = detectLanguageSyncRef.current(value);
                    const currentLang = languageRef.current;
                    const hasEditorFocus = monacoRef.current?.hasTextFocus() ?? false;

                    if (
                        quick &&
                        quick.monacoId !== currentLang &&
                        quick.confidence >= 0.9 &&
                        !hasEditorFocus
                    ) {
                        lastDetectedRef.current = quick.monacoId;
                        setLanguageRef.current(quick.monacoId);
                    }
                } catch (e) {
                    console.warn('[Editor] Heuristic failed:', e);
                }

                debouncedLanguageDetection(value, newVersion);
                debouncedRunner(value);
            }
        },
        [debouncedRunner, debouncedLanguageDetection, setCode, monacoRef, lastLocalCodeRef, lastCursorPositionRef]
    );

    return handler;
}

import { useCallback, useEffect, useRef } from 'react';
import type { Monaco } from '@monaco-editor/react';
import * as monaco from 'monaco-editor';
import type { editor } from 'monaco-editor';
import { configureMonaco } from '../../utils/monaco-config';
import { registerPythonLanguage } from '../../lib/python';
import { registerMonacoProviders, disposeMonacoProviders } from '../../lib/monacoProviders';
import { registerPythonMonacoProviders, disposePythonMonacoProviders } from '../../lib/python/pythonMonacoProviders';
import { registerPackageCommands } from '../../lib/monacoCommands';
import { setupTypeAcquisition } from '../../lib/ata';
import { createInlineCompletionProvider, registerAICodeActions } from '../../features/ai-agent';
import { useEditorTabsStore, useCodeStore } from '../../store/storeHooks';

export function useEditorLifecycle({
    setMonacoInstance,
    initializeModel,
    applyLanguageToMonaco,
    setLanguage,
    detectLanguageAsync,
    runCode,
    cleanupModels,
}: {
    setMonacoInstance: (instance: Monaco) => void;
    initializeModel: () => Promise<void>;
    applyLanguageToMonaco: (model: editor.ITextModel) => void;
    setLanguage: (lang: string) => void;
    detectLanguageAsync: (code: string) => Promise<any>;
    runCode: (code: string) => void;
    cleanupModels: (editorInstance: editor.IStandaloneCodeEditor) => void;
}) {
    const ataDisposeRef = useRef<(() => void) | null>(null);
    const inlineCompletionDisposableRef = useRef<monaco.IDisposable | null>(null);
    const aiCodeActionsDisposablesRef = useRef<monaco.IDisposable[]>([]);

    useEffect(() => {
        return () => {
            disposeMonacoProviders();
            disposePythonMonacoProviders();
            if (ataDisposeRef.current) {
                ataDisposeRef.current();
            }
            if (inlineCompletionDisposableRef.current) {
                inlineCompletionDisposableRef.current.dispose();
            }
            aiCodeActionsDisposablesRef.current.forEach((d) => d.dispose());
        };
    }, []);

    const handleEditorWillMount = useCallback(
        (monacoInstance: Monaco) => {
            configureMonaco(monacoInstance);

            setMonacoInstance(monacoInstance);
            registerPythonLanguage(monacoInstance);

            initializeModel().catch((err: any) => {
                console.warn('[Editor] Language detection model initialization failed:', err);
            });
        },
        [setMonacoInstance, initializeModel]
    );

    const handleEditorDidMount = useCallback(
        (editorInstance: editor.IStandaloneCodeEditor, monacoInstance: Monaco) => {
            const model = editorInstance.getModel();
            if (model) {
                applyLanguageToMonaco(model);
            }

            Object.assign(window, {
                monaco: monacoInstance,
                editor: editorInstance,
                useCodeStore: useCodeStore,
                useEditorTabsStore: useEditorTabsStore
            });

            const initialCode = editorInstance.getValue();
            if (initialCode && initialCode.trim().length > 10) {
                detectLanguageAsync(initialCode)
                    .then((detected: any) => {
                        const currentModel = editorInstance.getModel();
                        if (
                            currentModel &&
                            !currentModel.isDisposed() &&
                            detected.monacoId !== currentModel.getLanguageId()
                        ) {
                            monacoInstance.editor.setModelLanguage(currentModel, detected.monacoId);
                            setLanguage(detected.monacoId);
                        }
                    })
                    .catch(console.error);
            }

            ataDisposeRef.current = setupTypeAcquisition(monacoInstance);
            registerMonacoProviders(monacoInstance, editorInstance);
            registerPythonMonacoProviders(monacoInstance, editorInstance);

            cleanupModels(editorInstance);
            registerPackageCommands(monacoInstance, editorInstance, runCode);

            try {
                const inlineProvider = createInlineCompletionProvider(
                    monacoInstance as unknown as typeof import('monaco-editor')
                );
                inlineCompletionDisposableRef.current =
                    monacoInstance.languages.registerInlineCompletionsProvider(
                        { pattern: '**' },
                        inlineProvider
                    );
            } catch (err) {
                console.warn('[Editor] Failed to register AI inline completion provider:', err);
            }

            try {
                aiCodeActionsDisposablesRef.current = registerAICodeActions(
                    monacoInstance as unknown as typeof import('monaco-editor'),
                    editorInstance
                );
            } catch (err) {
                console.warn('[Editor] Failed to register AI code actions:', err);
            }
        },
        [
            runCode,
            cleanupModels,
            detectLanguageAsync,
            setLanguage,
            applyLanguageToMonaco
        ]
    );

    return {
        handleEditorWillMount,
        handleEditorDidMount
    };
}

import { useEditorTabsStore, useSettingsStore, getLanguageDisplayName } from '../store/storeHooks';
import { useAppStore } from '../store/index';
import { executionEngine } from '../lib/execution/ExecutionEngine';
import { useEffect, useCallback } from 'react';

export function useCodeRunner() {
  const { setTabPromptRequest } = useEditorTabsStore();

  const { showTopLevelResults, loopProtection, showUndefined, magicComments, workingDirectory } =
    useSettingsStore();

  // Remove global cancel on unmount to allow background tab execution
  useEffect(() => {
    return () => {
      // Background execution is supported, no global cancel here.
    };
  }, []);

  // Listen for JS input requests (synchronous prompt)
  useEffect(() => {
    if (!window.codeRunner?.onJSInputRequest) return;

    const unsubscribe = window.codeRunner.onJSInputRequest((request: any) => {
      if (request.id) {
        setTabPromptRequest(
          request.id,
          request.message,
          request.type === 'alert-request' ? 'alert' : 'text'
        );
      }
    });

    return () => {
      unsubscribe();
    };
  }, [setTabPromptRequest]);

  const runCode = useCallback(
    async (codeToRun?: string) => {
      const callerTabId = useEditorTabsStore.getState().activeTabId;
      if (!callerTabId) return;

      const debounceTimer = setTimeout(async () => {
        const { tabs, setTabPromptRequest, setTabExecuting, setTabResults, clearTabResults } = useEditorTabsStore.getState();
        const callerTab = tabs.find(t => t.id === callerTabId);

        const sourceCode = codeToRun ?? callerTab?.code ?? '';

        // Cancel previous execution for this tab ONLY
        executionEngine.cancel(callerTabId);
        setTabPromptRequest(callerTabId, null);

        // Detect language
        const detectLanguage = useAppStore.getState().language.detectLanguage;
        const detected = detectLanguage(sourceCode);
        const currentLang = detected.monacoId;

        if (!useAppStore.getState().language.isExecutable(currentLang)) {
          setTabExecuting(callerTabId, false);
          setTabResults(callerTabId, [
            {
              element: {
                content: `❌ Unsupported Language: ${getLanguageDisplayName(currentLang)} \n\nThis editor can execute JavaScript, TypeScript and Python code.\n\nDetected language: ${currentLang} \nSupported languages: javascript, typescript, python`,
              },
              type: 'error',
            },
          ]);
          return;
        }

        clearTabResults(callerTabId);
        setTabExecuting(callerTabId, true);

        const execLanguage = currentLang === 'python' ? 'python' : currentLang === 'typescript' ? 'typescript' : 'javascript';

        await executionEngine.run(
          callerTabId,
          sourceCode,
          execLanguage,
          {
            showUndefined,
            showTopLevelResults,
            loopProtection,
            magicComments,
            workingDirectory,
          },
          {
            onOutput: (result) => {
              useEditorTabsStore.getState().appendTabResult(callerTabId, {
                lineNumber: result.lineNumber,
                element: {
                  content: result.content,
                  jsType: result.jsType,
                  consoleType: result.consoleType as any,
                },
                type: result.type,
              });
            },
            onError: (errorMsg) => {
              useEditorTabsStore.getState().appendTabResult(callerTabId, {
                element: { content: errorMsg },
                type: 'error',
              });
            },
            onComplete: (historyData) => {
              useAppStore.getState().history.addToHistory(historyData);
              useEditorTabsStore.getState().setTabExecuting(callerTabId, false);
              useEditorTabsStore.getState().setTabPromptRequest(callerTabId, null);
            }
          }
        );

      }, 0); // No deferral wait needed.

      return () => clearTimeout(debounceTimer);
    },
    [
      showTopLevelResults,
      loopProtection,
      showUndefined,
      magicComments,
      workingDirectory,
    ]
  );

  return {
    runCode,
  };
}

/**
 * Monaco Providers for Python
 *
 * Provides IntelliSense features for Python code:
 * - Import detection and validation
 * - Missing package markers
 * - Hover information for packages
 * - Quick fix actions for installation
 */

import type { Monaco } from '@monaco-editor/react';
import type {
  editor,
  languages,
  IDisposable,
  IRange,
  Position,
  CancellationToken,
} from 'monaco-editor';
import { usePythonPackagesStore } from '../../store/storeHooks';
import { isPythonStdlibModule, extractPythonPackageName } from './pythonStdlib';

let pythonHoverProvider: IDisposable | null = null;
let pythonCodeActionProvider: IDisposable | null = null;

// ============================================================================
// PYTHON IMPORT EXTRACTION
// ============================================================================

/**
 * Extract package name from Python import statement at cursor position
 */
function getPythonPackageAtPosition(
  model: editor.ITextModel,
  position: Position
): { packageName: string; range: IRange } | null {
  const lineContent = model.getLineContent(position.lineNumber);

  // Python import patterns
  const patterns = [
    // from package import something
    {
      regex:
        /^\s*from\s+([a-zA-Z_][a-zA-Z0-9_]*(?:\.[a-zA-Z_][a-zA-Z0-9_]*)*)\s+import/g,
      group: 1,
    },
    // import package
    {
      regex:
        /^\s*import\s+([a-zA-Z_][a-zA-Z0-9_]*(?:\.[a-zA-Z_][a-zA-Z0-9_]*)*)/g,
      group: 1,
    },
    // import package as alias
    {
      regex:
        /^\s*import\s+([a-zA-Z_][a-zA-Z0-9_]*(?:\.[a-zA-Z_][a-zA-Z0-9_]*)*)\s+as\s+/g,
      group: 1,
    },
  ];

  for (const { regex, group } of patterns) {
    regex.lastIndex = 0;
    let match;
    while ((match = regex.exec(lineContent)) !== null) {
      const fullImport = match[group];
      const packageName = extractPythonPackageName(fullImport);

      // Skip stdlib modules
      if (isPythonStdlibModule(packageName)) {
        continue;
      }

      // Find the position of the package name in the line
      const importKeywordEnd = lineContent.indexOf(fullImport);
      if (importKeywordEnd === -1) continue;

      const packageStart = importKeywordEnd + 1;
      const packageEnd = packageStart + fullImport.length;

      // Check if cursor is within the package name
      if (
        position.column >= packageStart &&
        position.column <= packageEnd + 1
      ) {
        return {
          packageName,
          range: {
            startLineNumber: position.lineNumber,
            startColumn: packageStart,
            endLineNumber: position.lineNumber,
            endColumn: packageEnd + 1,
          },
        };
      }
    }
  }

  return null;
}

// ============================================================================
// PYTHON IMPORT VALIDATION
// ============================================================================

/**
 * Scan for Python imports and set markers for missing packages
 */
export function validatePythonImports(
  model: editor.ITextModel,
  monaco: Monaco
) {
  const code = model.getValue();
  const markers: editor.IMarkerData[] = [];
  const packages = usePythonPackagesStore.getState().packages;
  const missingPackages: string[] = [];

  // Split by lines for accurate position tracking
  const lines = code.split('\n');

  // Python import patterns
  const patterns = [
    // from package import something (including multiline)
    {
      regex:
        /^\s*from\s+([a-zA-Z_][a-zA-Z0-9_]*(?:\.[a-zA-Z_][a-zA-Z0-9_]*)*)\s+import/,
      group: 1,
    },
    // import package (can have multiple comma-separated)
    {
      regex:
        /^\s*import\s+([a-zA-Z_][a-zA-Z0-9_]*(?:\.[a-zA-Z_][a-zA-Z0-9_]*)*)/,
      group: 1,
    },
  ];

  lines.forEach((line, lineIndex) => {
    const lineNumber = lineIndex + 1;

    for (const { regex, group } of patterns) {
      regex.lastIndex = 0;
      const match = regex.exec(line);
      if (!match) continue;

      const fullImport = match[group];
      const packageName = extractPythonPackageName(fullImport);

      // Skip stdlib modules
      if (isPythonStdlibModule(packageName)) {
        continue;
      }

      // Check if installed
      const isInstalled = packages.some(
        (p: any) => p.name === packageName && p.isInstalled
      );

      if (!isInstalled) {
        // Add to missing packages list
        if (!missingPackages.includes(packageName)) {
          missingPackages.push(packageName);
        }

        // Find the position of the package name in the line
        const importStart = line.indexOf(fullImport);
        if (importStart === -1) continue;

        markers.push({
          severity: monaco.MarkerSeverity.Warning,
          message: `Python package "${packageName}" is not installed. Use micropip to install it.`,
          startLineNumber: lineNumber,
          startColumn: importStart + 1,
          endLineNumber: lineNumber,
          endColumn: importStart + fullImport.length + 1,
          code: 'missing-python-package',
          source: 'Python Package Manager',
        });
      }
    }

    // Handle comma-separated imports: import pkg1, pkg2, pkg3
    const multiImportMatch = line.match(/^\s*import\s+(.+)$/);
    if (multiImportMatch) {
      const importsPart = multiImportMatch[1];
      const imports = importsPart.split(',').map((s) =>
        s
          .trim()
          .split(/\s+as\s+/)[0]
          .trim()
      );

      let currentOffset = line.indexOf(importsPart);

      for (const imp of imports) {
        if (!imp) continue;

        const packageName = extractPythonPackageName(imp);

        // Skip stdlib modules
        if (isPythonStdlibModule(packageName)) {
          currentOffset = line.indexOf(imp, currentOffset) + imp.length;
          continue;
        }

        // Check if installed
        const isInstalled = packages.some(
          (p) => p.name === packageName && p.isInstalled
        );

        if (!isInstalled && !missingPackages.includes(packageName)) {
          missingPackages.push(packageName);

          const importStart = line.indexOf(imp, currentOffset);
          if (importStart !== -1) {
            markers.push({
              severity: monaco.MarkerSeverity.Warning,
              message: `Python package "${packageName}" is not installed.`,
              startLineNumber: lineNumber,
              startColumn: importStart + 1,
              endLineNumber: lineNumber,
              endColumn: importStart + imp.length + 1,
              code: 'missing-python-package',
              source: 'Python Package Manager',
            });
          }
        }

        currentOffset = line.indexOf(imp, currentOffset) + imp.length;
      }
    }
  });

  monaco.editor.setModelMarkers(model, 'python-package-manager', markers);

  // Update detected missing packages in store
  const currentMissing =
    usePythonPackagesStore.getState().detectedMissingPackages;
  const hasChanged =
    missingPackages.length !== currentMissing.length ||
    !missingPackages.every((p) => currentMissing.includes(p));

  if (hasChanged) {
    usePythonPackagesStore
      .getState()
      .setDetectedMissingPackages(missingPackages);
  }
}

// ============================================================================
// PYTHON MONACO PROVIDERS
// ============================================================================

export function registerPythonMonacoProviders(
  monaco: Monaco,
  editorInstance: editor.IStandaloneCodeEditor
) {
  // Dispose previous providers if they exist
  disposePythonMonacoProviders();

  const languageDisposables: IDisposable[] = [];

  // Subscribe to package store changes to re-validate
  const unsubscribePackages = usePythonPackagesStore.subscribe(() => {
    const model = editorInstance.getModel();
    if (model && model.getLanguageId() === 'python') {
      validatePythonImports(model, monaco);
    }
  });

  // Validate on content change (debounced)
  let debounceTimer: ReturnType<typeof setTimeout>;
  const contentChangeDisposable = editorInstance.onDidChangeModelContent(() => {
    const model = editorInstance.getModel();
    if (!model || model.getLanguageId() !== 'python') return;

    clearTimeout(debounceTimer);
    debounceTimer = setTimeout(() => {
      validatePythonImports(model, monaco);
    }, 1000);
  });

  // Validate on language change
  const languageChangeDisposable = editorInstance.onDidChangeModelLanguage(
    (e) => {
      if (e.newLanguage === 'python') {
        const model = editorInstance.getModel();
        if (model) {
          validatePythonImports(model, monaco);
        }
      } else {
        // Clear Python markers when switching away from Python
        const model = editorInstance.getModel();
        if (model) {
          monaco.editor.setModelMarkers(model, 'python-package-manager', []);
        }
      }
    }
  );

  languageDisposables.push({ dispose: unsubscribePackages });
  languageDisposables.push(contentChangeDisposable);
  languageDisposables.push(languageChangeDisposable);

  // Register Hover Provider for Python packages
  pythonHoverProvider = monaco.languages.registerHoverProvider('python', {
    provideHover: (
      model: editor.ITextModel,
      position: Position,
      token: CancellationToken
    ): languages.ProviderResult<languages.Hover> => {
      if (token.isCancellationRequested) {
        return null;
      }

      const packageInfo = getPythonPackageAtPosition(model, position);
      if (!packageInfo) {
        return null;
      }

      const { packageName, range } = packageInfo;
      const packages = usePythonPackagesStore.getState().packages;
      const installedPkg = packages.find((p) => p.name === packageName);

      const contents: { value: string; isTrusted?: boolean }[] = [];

      // Header with package name
      contents.push({
        value: `### 🐍 \`${packageName}\``,
        isTrusted: true,
      });

      // Installation status
      let statusText: string;
      if (installedPkg) {
        if (installedPkg.installing) {
          statusText = '**Status:** ⏳ Installing via micropip...';
        } else if (installedPkg.error) {
          statusText = `**Status:** ❌ Error: ${installedPkg.error}`;
        } else {
          statusText = '**Status:** ✅ Installed';
          if (installedPkg.version) {
            statusText += `\n\n**Version:** \`${installedPkg.version}\``;
          }
        }
      } else {
        statusText =
          '**Status:** ⚠️ Not installed\n\n*Use Quick Fix (Ctrl+.) to install via micropip*';
      }

      contents.push({
        value: statusText,
        isTrusted: true,
      });

      // PyPI link
      contents.push({
        value: `\n\n[🔍 View on PyPI](https://pypi.org/project/${packageName}/)`,
        isTrusted: true,
      });

      // Quick actions hint
      contents.push({
        value: '\n\n---\n\n💡 Press **Ctrl+.** for quick actions',
        isTrusted: true,
      });

      return {
        contents,
        range,
      };
    },
  });

  // Register Code Action Provider for Python packages
  pythonCodeActionProvider = monaco.languages.registerCodeActionProvider(
    'python',
    {
      provideCodeActions: (
        model: editor.ITextModel,
        range: IRange,
        context: languages.CodeActionContext,
        token: CancellationToken
      ): languages.ProviderResult<languages.CodeActionList> => {
        if (token.isCancellationRequested) {
          return {
            actions: [],
            dispose: () => {
              /* no-op */
            },
          };
        }

        const actions: languages.CodeAction[] = [];
        const position = model.getPositionAt(
          model.getOffsetAt({
            lineNumber: range.startLineNumber,
            column: range.startColumn,
          })
        );
        let packageInfo = getPythonPackageAtPosition(model, position);

        // Fallback: Check markers if getPythonPackageAtPosition failed
        if (!packageInfo) {
          const marker = context.markers.find(
            (m) => m.code === 'missing-python-package'
          );
          if (marker) {
            const match = marker.message.match(
              /Python package "([^"]+)" is not installed/
            );
            if (match) {
              packageInfo = {
                packageName: match[1],
                range: {
                  startLineNumber: marker.startLineNumber,
                  startColumn: marker.startColumn,
                  endLineNumber: marker.endLineNumber,
                  endColumn: marker.endColumn,
                },
              };
            }
          }
        }

        if (!packageInfo) {
          return {
            actions: [],
            dispose: () => {
              /* no-op */
            },
          };
        }

        const { packageName } = packageInfo;
        const packages = usePythonPackagesStore.getState().packages;
        const pkg = packages.find((p) => p.name === packageName);

        // Find relevant diagnostics
        const diagnostics = context.markers.filter(
          (m) =>
            m.code === 'missing-python-package' &&
            m.message.includes(`"${packageName}"`)
        );

        if (!pkg || (!pkg.isInstalled && !pkg.installing)) {
          // Package not installed
          actions.push({
            title: `$(cloud-download) Install "${packageName}" (micropip)`,
            kind: 'quickfix',
            diagnostics,
            isPreferred: true,
            command: {
              id: 'cheeseJS.installPythonPackage',
              title: 'Install Python Package',
              arguments: [packageName],
            },
          });

          actions.push({
            title: `$(play) Install "${packageName}" and run code`,
            kind: 'quickfix',
            diagnostics,
            command: {
              id: 'cheeseJS.installPythonPackageAndRun',
              title: 'Install Python Package and Run',
              arguments: [packageName],
            },
          });

          actions.push({
            title: `$(link-external) View "${packageName}" on PyPI`,
            kind: 'quickfix',
            diagnostics,
            command: {
              id: 'cheeseJS.viewOnPyPI',
              title: 'View on PyPI',
              arguments: [packageName],
            },
          });
        } else if (pkg.error) {
          // Package has error
          actions.push({
            title: `$(refresh) Retry installing "${packageName}"`,
            kind: 'quickfix',
            diagnostics,
            isPreferred: true,
            command: {
              id: 'cheeseJS.retryPythonInstall',
              title: 'Retry Install',
              arguments: [packageName],
            },
          });

          actions.push({
            title: `$(link-external) View "${packageName}" on PyPI`,
            kind: 'quickfix',
            diagnostics,
            command: {
              id: 'cheeseJS.viewOnPyPI',
              title: 'View on PyPI',
              arguments: [packageName],
            },
          });
        } else if (pkg.installing) {
          // Package is installing
          actions.push({
            title: `$(sync~spin) "${packageName}" is being installed...`,
            kind: 'empty',
            diagnostics,
          });
        } else {
          // Package is installed
          actions.push({
            title: `$(check) "${packageName}" is installed${pkg.version ? ` (v${pkg.version})` : ''}`,
            kind: 'empty',
            diagnostics,
          });

          actions.push({
            title: `$(link-external) View "${packageName}" on PyPI`,
            kind: 'quickfix',
            diagnostics,
            command: {
              id: 'cheeseJS.viewOnPyPI',
              title: 'View on PyPI',
              arguments: [packageName],
            },
          });
        }

        return {
          actions,
          dispose: () => {
            /* no-op */
          },
        };
      },
    }
  );

  // Validate initially if Python
  const model = editorInstance.getModel();
  if (model && model.getLanguageId() === 'python') {
    validatePythonImports(model, monaco);
  }

  // Store disposables for cleanup
  const originalHoverDispose = pythonHoverProvider;
  pythonHoverProvider = {
    dispose: () => {
      originalHoverDispose?.dispose();
      languageDisposables.forEach((d) => d.dispose());
    },
  } as IDisposable;
}

export function disposePythonMonacoProviders() {
  pythonHoverProvider?.dispose();
  pythonCodeActionProvider?.dispose();
  pythonHoverProvider = null;
  pythonCodeActionProvider = null;
}

import { create, type StoreApi, type UseBoundStore, type StateCreator } from 'zustand';

export const MAX_INSTALL_ATTEMPTS = 3;

// ============================================================================
// Generic package types
// ============================================================================

export interface BasePackageError {
  code: string;
  message: string;
  timestamp: number;
}

export interface BasePackageInfo {
  name: string;
  version?: string;
  installing: boolean;
  isInstalled: boolean;
  error?: string;
  installAttempts: number;
  lastError?: BasePackageError;
}

export interface BasePackagesState<
  T extends BasePackageInfo = BasePackageInfo,
> {
  packages: T[];
  detectedMissingPackages: string[];
  isInstalling: boolean;
  addPackage: (name: string, version?: string) => void;
  setDetectedMissingPackages: (packages: string[]) => void;
  setPackageInstalling: (name: string, installing: boolean) => void;
  setPackageInstalled: (name: string, version?: string) => void;
  setPackageError: (name: string, error?: string, errorCode?: string) => void;
  removePackage: (name: string) => void;
  resetPackageAttempts: (name: string) => void;
  canRetryInstall: (name: string) => boolean;
  incrementInstallAttempt: (name: string) => number;
}

// ============================================================================
// Slice Creator Factory
// ============================================================================

export const createPackageSlice = <
  T extends BasePackageInfo = BasePackageInfo,
>(): StateCreator<BasePackagesState<T>> => (set, get) => ({
  packages: [],
  detectedMissingPackages: [],
  isInstalling: false,

  setDetectedMissingPackages: (packages: string[]) => {
    set({ detectedMissingPackages: packages });
  },

  addPackage: (name: string, version?: string) => {
    set((state) => {
      const existing = state.packages.find((pkg) => pkg.name === name);
      if (existing) {
        if (
          existing.error &&
          existing.installAttempts < MAX_INSTALL_ATTEMPTS
        ) {
          return {
            packages: state.packages.map((pkg) =>
              pkg.name === name
                ? {
                  ...pkg,
                  error: undefined,
                  installing: false,
                  isInstalled: false,
                }
                : pkg
            ),
          };
        }
        return state;
      }
      return {
        packages: [
          ...state.packages,
          {
            name,
            version,
            installing: false,
            isInstalled: false,
            installAttempts: 0,
          } as T,
        ],
      };
    });
  },

  setPackageInstalling: (name: string, installing: boolean) => {
    set((state) => {
      const updatedPackages = state.packages.map((pkg) =>
        pkg.name === name ? { ...pkg, installing, error: undefined } : pkg
      );
      const anyInstalling = updatedPackages.some((pkg) => pkg.installing);
      return {
        packages: updatedPackages,
        isInstalling: anyInstalling,
      };
    });
  },

  setPackageInstalled: (name: string, version?: string) => {
    set((state) => {
      const updatedPackages = state.packages.map((pkg) =>
        pkg.name === name
          ? {
            ...pkg,
            installing: false,
            isInstalled: true,
            error: undefined,
            version: version || pkg.version,
            lastError: undefined,
          }
          : pkg
      );
      const anyInstalling = updatedPackages.some((pkg) => pkg.installing);
      return {
        packages: updatedPackages,
        isInstalling: anyInstalling,
      };
    });
  },

  setPackageError: (name: string, error?: string, errorCode?: string) => {
    set((state) => {
      const updatedPackages = state.packages.map((pkg) =>
        pkg.name === name
          ? {
            ...pkg,
            error,
            installing: false,
            isInstalled: false,
            lastError: error
              ? {
                code: errorCode || 'INSTALL_ERROR',
                message: error,
                timestamp: Date.now(),
              }
              : undefined,
          }
          : pkg
      );
      const anyInstalling = updatedPackages.some((pkg) => pkg.installing);
      return {
        packages: updatedPackages,
        isInstalling: anyInstalling,
      };
    });
  },

  removePackage: (name: string) => {
    set((state) => ({
      packages: state.packages.filter((pkg) => pkg.name !== name),
    }));
  },

  resetPackageAttempts: (name: string) => {
    set((state) => ({
      packages: state.packages.map((pkg) =>
        pkg.name === name
          ? {
            ...pkg,
            installAttempts: 0,
            error: undefined,
            lastError: undefined,
          }
          : pkg
      ),
    }));
  },

  canRetryInstall: (name: string) => {
    const state = get();
    const pkg = state.packages.find((p) => p.name === name);
    if (!pkg) return true;
    return pkg.installAttempts < MAX_INSTALL_ATTEMPTS;
  },

  incrementInstallAttempt: (name: string) => {
    let attempts = 0;
    set((state) => {
      const pkg = state.packages.find((p) => p.name === name);
      attempts = (pkg?.installAttempts || 0) + 1;
      return {
        packages: state.packages.map((p) =>
          p.name === name ? { ...p, installAttempts: attempts } : p
        ),
      };
    });
    return attempts;
  },
});

export const partializePackages = (state: BasePackagesState<any>) => ({
  packages: state.packages,
});

export function createPackageStore<
  T extends BasePackageInfo = BasePackageInfo,
>(): UseBoundStore<StoreApi<BasePackagesState<T>>> {
  return create<BasePackagesState<T>>(createPackageSlice<T>());
}



// ============================================================================
// Generic selectors
// ============================================================================

export const selectPendingPackages = <T extends BasePackageInfo>(
  state: BasePackagesState<T>
) => state.packages.filter((p) => !p.isInstalled);

export const selectVisibleMissingPackages = <T extends BasePackageInfo>(
  state: BasePackagesState<T>
) =>
  state.detectedMissingPackages.filter((pkgName) => {
    const existingPkg = state.packages.find((p) => p.name === pkgName);
    return !existingPkg?.isInstalled && !existingPkg;
  });

export const selectPackageByName =
  <T extends BasePackageInfo>(name: string) =>
    (state: BasePackagesState<T>) =>
      state.packages.find((p) => p.name === name);

import { create, StateCreator } from 'zustand';
import { persist, subscribeWithSelector, createJSONStorage } from 'zustand/middleware';
import { CodeState, createCodeSlice, partializeCode } from './useCodeStore';
import { SettingsState, createSettingsSlice, partializeSettings } from './useSettingsStore';
import { HistoryState, createHistorySlice, partializeHistory } from './useHistoryStore';
import { SnippetsState, createSnippetsSlice, partializeSnippets } from './useSnippetsStore';
import { LanguageState, createLanguageSlice, partializeLanguage } from './useLanguageStore';
import { ChatState, createChatSlice, partializeChat } from './useChatStore';
import { createAISettingsSlice, partializeAISettings, type AISettingsState } from './useAISettingsStore';
import { createRagSlice, partializeRag, initRagProgressListener, type RagState } from './useRagStore';
import { createPackagesSlice, type PackagesState, partializePackages } from './usePackagesStore';
import { createPythonPackagesSlice, type PythonPackagesState } from './usePythonPackagesStore';
import { createEditorTabsSlice, type EditorTabsState, partializeEditorTabs } from './useEditorTabsStore';
import { idbStorage } from './idbStorage';

export interface AppState {
    code: CodeState;
    settings: SettingsState;
    history: HistoryState;
    snippets: SnippetsState;
    language: LanguageState;
    chat: ChatState;
    aiSettings: AISettingsState;
    rag: RagState;
    packages: PackagesState;
    pythonPackages: PythonPackagesState;
    editorTabs: EditorTabsState;
}

// Helper to wrap set/get for nested slices
function createNestedSlice<TState, TSlice>(
    set: any,
    get: any,
    sliceKey: keyof TState,
    sliceCreator: StateCreator<TSlice>
): TSlice {
    const nestedSet = (partial: any, replace?: boolean) => {
        set((state: any) => {
            const nextSlice = typeof partial === 'function' ? partial(state[sliceKey]) : partial;
            return {
                ...state,
                [sliceKey]: replace ? nextSlice : { ...state[sliceKey], ...nextSlice }
            };
        }, replace);
    };
    const nestedGet = () => get()[sliceKey];
    return sliceCreator(nestedSet as any, nestedGet as any, {} as any);
}

export const useAppStore = create<AppState>()(
    subscribeWithSelector(
        persist(
            (set, get) => ({
                code: createNestedSlice(set, get, 'code', createCodeSlice),
                settings: createNestedSlice(set, get, 'settings', createSettingsSlice),
                history: createNestedSlice(set, get, 'history', createHistorySlice),
                snippets: createNestedSlice(set, get, 'snippets', createSnippetsSlice),
                language: createNestedSlice(set, get, 'language', createLanguageSlice),
                chat: createNestedSlice(set, get, 'chat', createChatSlice),
                aiSettings: createNestedSlice(set, get, 'aiSettings', createAISettingsSlice),
                rag: createNestedSlice(set, get, 'rag', createRagSlice),
                packages: createNestedSlice(set, get, 'packages', createPackagesSlice),
                pythonPackages: createNestedSlice(set, get, 'pythonPackages', createPythonPackagesSlice),
                editorTabs: createNestedSlice(set, get, 'editorTabs', createEditorTabsSlice),
            }),
            {
                name: 'cheesejs-app-storage',
                storage: createJSONStorage(() => idbStorage),
                partialize: (state) => ({
                    code: partializeCode(state.code),
                    settings: partializeSettings(state.settings),
                    history: partializeHistory(state.history),
                    snippets: partializeSnippets(state.snippets),
                    language: partializeLanguage(state.language),
                    chat: partializeChat(state.chat),
                    aiSettings: partializeAISettings(state.aiSettings),
                    rag: partializeRag(state.rag),
                    packages: partializePackages(state.packages),
                    pythonPackages: partializePackages(state.pythonPackages),
                    editorTabs: partializeEditorTabs(state.editorTabs),
                }),
                merge: (persistedState: any, currentState: AppState) => {
                    if (!persistedState) return currentState;

                    // Helper to merge a slice while preserving functions from currentState
                    const mergeSlice = (key: keyof AppState) => {
                        if (persistedState[key] && currentState[key]) {
                            return {
                                ...currentState[key],
                                ...persistedState[key]
                            };
                        }
                        return persistedState[key] || currentState[key];
                    };

                    return {
                        ...currentState,
                        code: mergeSlice('code'),
                        settings: mergeSlice('settings'),
                        history: mergeSlice('history'),
                        snippets: mergeSlice('snippets'),
                        language: mergeSlice('language'),
                        chat: mergeSlice('chat'),
                        aiSettings: mergeSlice('aiSettings'),
                        rag: mergeSlice('rag'),
                        packages: mergeSlice('packages'),
                        pythonPackages: mergeSlice('pythonPackages'),
                        editorTabs: mergeSlice('editorTabs')
                    } as AppState;
                }
            }
        )
    )
);


// Initialize rag progress listener
initRagProgressListener(useAppStore);

